<script>document.addEventListener('DOMContentLoaded',()=>{const h=window.eduplay.history().sort((a,b)=>Number(b.score)-Number(a.score)).slice(0,20),body=document.querySelector('[data-ranking-body]');if(!h.length){document.querySelector('.table-wrap').classList.add('hidden');document.querySelector('[data-ranking-empty]').classList.remove('hidden');return}h.forEach((x,i)=>{const tr=document.createElement('tr');[i<3?['🥇','🥈','🥉'][i]:i+1,x.type,x.score,new Date(x.date).toLocaleDateString('id-ID')].forEach(v=>{const td=document.createElement('td');td.textContent=v;tr.appendChild(td)});body.appendChild(tr)})})</script>
